import inspect
import functools
import typing

def _check_type(value, expected_type, param_name="return value"):
    if expected_type is typing.Any:
        return

    if typing.get_origin(expected_type) is typing.Union:
        union_types = typing.get_args(expected_type)
        if not isinstance(value, union_types):
            raise TypeError(
                f"Type mismatch for {param_name}: "
                f"Expected one of {union_types}, got {type(value).__name__}"
            )
        return

    origin = typing.get_origin(expected_type)
    if origin is not None:
        if not isinstance(value, origin):
            raise TypeError(
                f"Type mismatch for {param_name}: "
                f"Expected base type {origin.__name__} (from {expected_type}), "
                f"got {type(value).__name__}"
            )
        return

    if not isinstance(value, expected_type):
        raise TypeError(
            f"Type mismatch for {param_name}: "
            f"Expected {expected_type.__name__}, got {type(value).__name__}"
        )

def type_check(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        sig = inspect.signature(func)
        bound_args = sig.bind(*args, **kwargs)
        bound_args.apply_defaults()

        for name, value in bound_args.arguments.items():
            param = sig.parameters[name]
            if param.annotation is not inspect.Parameter.empty:
                _check_type(value, param.annotation, f"argument '{name}'")

        result = func(*args, **kwargs)

        if sig.return_annotation is not inspect.Parameter.empty:
            _check_type(result, sig.return_annotation, "return value")

        return result
    return wrapper
